def _check_cron_inline(
    a: AddedLine,
    text: str,
) -> tuple[str, int, str, str] | None:
    stripped = text.rstrip()
    if not stripped:
        return None
    if CRON_SHEBANG_OR_COMMENT.match(stripped):
        return None
    if CRON_ENV.match(stripped):
        return None
    if not CRON_LINE.match(stripped):
        return None
    if not CRON_OK.search(stripped):
        return (a.path, a.lineno, "cron-no-log-redirect", stripped)
    return None

def _classify_except_body(
    nxt: AddedLine,
    lines: dict[int, AddedLine],
    lineno: int,
    header_indent: int,
) -> str | None:
    """Classify the body of an except block.

    Returns the pattern_id if a violation is found, None otherwise.
    """
    bm = _BODY_RE.match(nxt.text)
    if bm:
        body_indent = len(bm.group("indent"))
        if body_indent <= header_indent:
            return None
        stmt = bm.group(2)
        if stmt.startswith("return"):
            return "py-except-return-none"
        return _BODY_MAP.get(stmt, "py-except-return-none")

    for rgx, pid in _NON_SILENT_CHECKS:
        match = rgx.match(nxt.text)
        if not match:
            continue
        body_indent = len(match.group("indent"))
        if body_indent > header_indent and not _is_follow_up_blocked(
            lines, lineno, body_indent
        ):
            return pid
        break
    return None

def _check_catch_body(
    lines: dict[int, AddedLine],
    lineno: int,
    header_indent: int,
) -> bool:
    """Check lines after a catch header for silent return.

    Returns True if a silent-return violation is found.
    """
    for offset in range(1, 4):
        body = lines.get(lineno + offset)
        if body is None:
            continue
        if body.text.strip() == "}":
            return False
        if JS_CONSOLE_LOG.search(body.text) or JS_THROW.search(body.text):
            return False
        rm = JS_SILENT_RETURN.match(body.text)
        if rm:
            body_indent = len(rm.group("indent"))
            if body_indent <= header_indent:
                continue
            return True
        if body.text.strip() and not body.text.strip().startswith("//"):
            return False
    return False

def detect_ansible_tasks(added_lines):
    """Multi-line detector: find shell/command tasks without register:.

    Returns list of (header_addedline, pattern_id).
    """
    violations = []
    lines = added_lines
    i = 0
    while i < len(lines):
        line = lines[i]
        text = line.text

        if _SHELL_RE.search(text) or _COMMAND_RE.search(text):
            has_register, has_failed_when = _scan_task_flags(lines, i)
            if not has_register and not has_failed_when:
                if _check_changed_when_false(lines, i):
                    violations.append((line, "ansible-shell-no-register"))
                else:
                    violations.append((line, "ansible-shell-no-guard"))

        i += 1

    return violations
